INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3001, 0.0, "ヤマト", "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", -416.5, 1, 2.1, 2, 100, 3001100, "2024/10/31 12:00:00", 130011);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3001, 0.0, "ヤマト", "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", -416.5, 4, 5.68, 2, 101, 3001101, "2024/10/31 12:00:00", 130011);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3001, 0.0, "ヤマト", "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", -416.5, 1, 0.0, 1, 102, 3001102, "2024/10/31 12:00:00", 130011);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3002, 0.0, "フブキ", "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", -416.5, 1, 0.0, 1, 100, 3002100, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3002, 0.0, "フブキ", "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", -416.5, 1, 0.0, 1, 101, 3002101, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3002, 0.0, "フブキ", "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", -416.5, 5, 8.53, 2, 102, 3002102, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3002, 0.0, "フブキ", "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", -416.5, 7, 5.67, 1, 103, 3002103, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3002, 0.0, "フブキ", "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", -416.5, 1, 0.0, 1, 104, 3002104, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3004, 0.0, "フブキ", "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", -416.5, 3, 0.0, 3, 300, 3002300, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3005, 0.0, "フブキ", "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", -416.5, 7, 0.0, 7, 301, 3002400, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3003, 0.0, "フブキ", "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", -416.5, 2, 4.4, 1, 200, 3003200, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3003, 0.0, "フブキ", "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", -416.5, 7, 0.0, 7, 201, 3003201, "2024/10/31 12:00:00", 130211);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", 3003, 0.0, "フブキ", "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", -416.5, 1, 5.6, 2, 202, 3003202, "2024/10/31 12:00:00", 130211);
